function settle(Currency currency, IPoolManager poolManager, address payer, uint256 amount, bool burn) internal {
    // Early return when amount is 0 given that some tokens may revert in this case
    if (amount == 0) return;

    // For native currencies or burns, calling sync is not required
    // Short circuit for ERC-6909 burns to support ERC-6909-wrapped native tokens
    if (burn) {
        poolManager.burn(payer, currency.toId(), amount);
    } else if (currency.isAddressZero()) {
        poolManager.sync(currency);
        poolManager.settle{value: amount}();
    } else {
        poolManager.sync(currency);
        if (payer != address(this)) {
            IERC20(Currency.unwrap(currency)).safeTransferFrom(payer, address(poolManager), amount);
        } else {
            IERC20(Currency.unwrap(currency)).safeTransfer(address(poolManager), amount);
        }
        poolManager.settle();
    }
}

if (prevId == address(0) && nextId == address(0)) {
    // Insert as head and tail
    self.head = _id;
    self.tail = _id;
} else if (prevId == address(0)) {
    // Insert before `prevId` as the head
    self.nodes[_id].nextId = self.head;
    self.nodes[self.head].prevId = _id;
    self.head = _id;
} else if (nextId == address(0)) {
    // Insert after `nextId` as the tail
    self.nodes[_id].prevId = self.tail;
    self.nodes[self.tail].nextId = _id;
    self.tail = _id;
} else {
    // Insert at insert position between `prevId` and `nextId`
    self.nodes[_id].nextId = nextId;
    self.nodes[_id].prevId = prevId;
    self.nodes[prevId].nextId = _id;
    self.nodes[nextId].prevId = _id;
}

function upgradeProxyTo(address proxy, address newImpl, bytes memory data) internal {
    Vm vm = Vm(Utils.CHEATCODE_ADDRESS);

    bytes32 adminSlot = vm.load(proxy, ADMIN_SLOT);
    if (adminSlot == bytes32(0)) {
        string memory upgradeInterfaceVersion = getUpgradeInterfaceVersion(proxy);
        if (upgradeInterfaceVersion.equal("5.0.0") || data.length > 0) {
            IUpgradeableProxy(proxy).upgradeToAndCall(newImpl, data);
        } else {
            IUpgradeableProxy(proxy).upgradeTo(newImpl);
        }
    } else {
        address admin = address(uint160(uint256(adminSlot)));
        string memory upgradeInterfaceVersion = getUpgradeInterfaceVersion(admin);
        if (upgradeInterfaceVersion.equal("5.0.0") || data.length > 0) {
            IProxyAdmin(admin).upgradeAndCall(proxy, newImpl, data);
        } else {
            IProxyAdmin(admin).upgrade(proxy, newImpl);
        }
    }
}

function _toShortName(string memory name) private pure returns (string memory) {
    Vm vm = Vm(CHEATCODE_ADDRESS);
    if (name.endsWith(".sol") && name.count(".sol") == 1) {
        return vm.replace(name, ".sol", "");
    } else if (name.count(":") == 1) {
        return vm.split(name, ":")[1];
    } else if (name.endsWith(".json") && name.count(".json") == 1) {
        string[] memory parts = vm.split(name, "/");
        string memory jsonName = parts[parts.length - 1];
        return vm.replace(jsonName, ".json", "");
    } else {
        revert(
            string(
                abi.encodePacked(
                    "Contract name ",
                    name,
                    " must be in the format MyContract.sol:MyContract or MyContract.sol or out/MyContract.sol/MyContract.json"
                )
            )
        );
    }
}

function _calculateLiquidityPenalty(BalanceDelta feeDelta, uint48 lastAddedLiquidityBlock)
        internal
        virtual
        returns (BalanceDelta liquidityPenalty)
    {
        uint48 currentBlockNumber = _getBlockNumber();

        unchecked {
            uint256 amount0LiquidityPenalty = FullMath.mulDiv(
                SafeCast.toUint128(feeDelta.amount0()),
                blockNumberOffset - (currentBlockNumber - lastAddedLiquidityBlock), // won't overflow.
                blockNumberOffset
            );
            uint256 amount1LiquidityPenalty = FullMath.mulDiv(
                SafeCast.toUint128(feeDelta.amount1()),
                blockNumberOffset - (currentBlockNumber - lastAddedLiquidityBlock), // won't overflow.
                blockNumberOffset
            );

            // Although the amounts are returned as uint256, they must fit in int128, since they are fee rewards.
            liquidityPenalty = toBalanceDelta(amount0LiquidityPenalty.toInt128(), amount1LiquidityPenalty.toInt128());
        }
    }

if (lesserKey == bytes32(0) && isValueBetween(list, value, lesserKey, list.list.tail)) {
  return (lesserKey, list.list.tail);
} else if (
  greaterKey == bytes32(0) && isValueBetween(list, value, list.list.head, greaterKey)
) {
  return (list.list.head, greaterKey);
} else if (
  lesserKey != bytes32(0) &&
  isValueBetween(list, value, lesserKey, list.list.elements[lesserKey].nextKey)
) {
  return (lesserKey, list.list.elements[lesserKey].nextKey);
} else if (
  greaterKey != bytes32(0) &&
  isValueBetween(list, value, list.list.elements[greaterKey].previousKey, greaterKey)
) {
  return (list.list.elements[greaterKey].previousKey, greaterKey);
} else {
  require(false, "get lesser and greater failure");
}

if (remainingToTargetRatio.gt(FixidityLib.fixed1())) {
  FixidityLib.Fraction memory delta = remainingToTargetRatio
    .subtract(FixidityLib.fixed1())
    .multiply(rewardsMultiplierParams.adjustmentFactors.underspend);
  FixidityLib.Fraction memory multiplier = FixidityLib.fixed1().add(delta);
  if (multiplier.lt(rewardsMultiplierParams.max)) {
    return multiplier;
  } else {
    return rewardsMultiplierParams.max;
  }
} else if (remainingToTargetRatio.lt(FixidityLib.fixed1())) {
  FixidityLib.Fraction memory delta = FixidityLib
    .fixed1()
    .subtract(remainingToTargetRatio)
    .multiply(rewardsMultiplierParams.adjustmentFactors.overspend);
  if (delta.lt(FixidityLib.fixed1())) {
    return FixidityLib.fixed1().subtract(delta);
  } else {
    return FixidityLib.wrap(0);
  }
} else {
  return FixidityLib.fixed1();
}

