if (tracker.countReceived >= getThreshold()) {
    // prevent re-entry
    tracker.executed = true;

    bytes memory call = abi.encodeCall(
        IERC7786Recipient.receiveMessage,
        (id, originalSender, unwrappedPayload)
    );
    // slither-disable-next-line reentrancy-no-eth
    (, address target) = recipient.parseEvmV1();
    (bool success, bytes memory returndata) = target.call(call);

    if (!success) {
        // rollback to enable retry
        tracker.executed = false;
        emit ExecutionFailed(id);
    } else if (bytes32(returndata) == bytes32(IERC7786Recipient.receiveMessage.selector)) {
        // call successful and correct value returned
        emit ExecutionSuccess(id);
    } else {
        // call successful but invalid value returned, we need to revert the subcall
        revert ERC7786OpenBridgeInvalidExecutionReturnValue();
    }
}

unchecked {
    if (!facetCut.target.isContract())
        revert DiamondProxyWritable__TargetHasNoCode();

    for (uint256 i; i < facetCut.selectors.length; i++) {
        bytes4 selector = facetCut.selectors[i];
        bytes32 selectorInfo = $.selectorInfo[selector];
        address oldFacetAddress = address(bytes20(selectorInfo));

        if (oldFacetAddress == address(0))
            revert DiamondProxyWritable__SelectorNotFound();
        if (oldFacetAddress == address(this))
            revert DiamondProxyWritable__SelectorIsImmutable();
        if (oldFacetAddress == facetCut.target)
            revert DiamondProxyWritable__ReplaceTargetIsIdentical();

        // replace old facet address
        $.selectorInfo[selector] =
            (selectorInfo & CLEAR_ADDRESS_MASK) |
            bytes20(facetCut.target);
    }
}

if (totalSupply == 0) {
    // For first deposit, just use the amounts desired
    amount0 = amount0Desired;
    amount1 = amount1Desired;
    shares = Math.max(amount0, amount1);
} else if (total0 == 0) {
    amount1 = amount1Desired;
    shares = amount1.mul(totalSupply).div(total1);
} else if (total1 == 0) {
    amount0 = amount0Desired;
    shares = amount0.mul(totalSupply).div(total0);
} else {
    uint256 cross = Math.min(amount0Desired.mul(total1), amount1Desired.mul(total0));
    require(cross > 0, "cross");

    // Round up amounts
    amount0 = cross.sub(1).div(total1).add(1);
    amount1 = cross.sub(1).div(total0).add(1);
    shares = cross.mul(totalSupply).div(total0).div(total1);
}

try IIrmV2(params.irm).borrowRateView(params, market) returns (
    uint256 borrowRate
) {
    // Convert rate per second to APY
    // borrowApy = (1 + borrowRate)^SECONDS_PER_YEAR - 1
    // Simplified: borrowApy ≈ borrowRate * SECONDS_PER_YEAR (for small rates)
    borrowApy = borrowRate * SECONDS_PER_YEAR;

    // Calculate utilization
    uint256 utilization = market.totalBorrowAssets > 0
        ? (uint256(market.totalBorrowAssets) * WAD) /
            uint256(market.totalSupplyAssets)
        : 0;

    // Supply APY = Borrow APY * utilization * (1 - fee)
    if (utilization > 0) {
        supplyApy = _mulWad(
            _mulWad(borrowApy, utilization),
            WAD - uint256(market.fee)
        );
    }
} catch {
    return (0, 0);
}

